+/** Create a value-based entity filter from data-bearing trait dependencies. */
+export function createPredicate<T extends Trait[]>(
+    dependencies: T,
+    test: (data: PredicateData<T>) => boolean
+): Predicate<T> {
+    for (const dependency of dependencies) {
+        if (isRelation(dependency) || dependency[$internal].type === 'tag') {
+            throw new Error('Koota: Predicates cannot depend on tags or relations.');
+        }
+    }
+
+    const predicate = createModifier('predicate', ++predicateId, dependencies) as Predicate<T>;
+    predicate.predicate = test;
+    return predicate;
+}
+
+/** Evaluate a predicate, treating a missing dependency as false. */
+export function evaluatePredicate(world: World, entity: Entity, predicate: Predicate): boolean {
+    const values: unknown[] = [];
+    for (const dependency of predicate.traits) {
+        if (!hasTrait(world, entity, dependency)) return false;
+        const ctx = dependency[$internal];
+        values.push(ctx.get(entity as number, getStore(world, dependency)));
+    }
+    return predicate.predicate(values as PredicateData<any>);
